/**
 * Minimal strict-FHIR typing for Composition, DocumentReference, and Communication.
 * These interfaces intentionally cover the subset used by frontend/backend flows today.
 */
export type FhirReference = {
    reference?: string;
    type?: string;
    display?: string;
};
export type FhirCoding = {
    system?: string;
    code?: string;
    display?: string;
};
export type FhirCodeableConcept = {
    coding?: FhirCoding[];
    text?: string;
};
export type FhirAttachment = {
    contentType?: string;
    language?: string;
    data?: string;
    url?: string;
    title?: string;
    creation?: string;
};
export interface FhirCompositionResource {
    resourceType: 'Composition';
    id?: string;
    status?: string;
    type?: FhirCodeableConcept;
    subject?: FhirReference;
    date?: string;
    author?: FhirReference[];
    title?: string;
    section?: Array<{
        title?: string;
        code?: FhirCodeableConcept;
        text?: {
            status?: string;
            div?: string;
        };
        entry?: FhirReference[];
    }>;
}
export interface FhirDocumentReferenceResource {
    resourceType: 'DocumentReference';
    id?: string;
    status?: string;
    identifier?: Array<{
        system?: string;
        value?: string;
    }>;
    type?: FhirCodeableConcept;
    category?: FhirCodeableConcept[];
    subject?: FhirReference;
    date?: string;
    author?: FhirReference[];
    attester?: Array<{
        mode?: string;
        party?: FhirReference;
        time?: string;
    }>;
    description?: string;
    context?: {
        encounter?: FhirReference[];
        event?: FhirCodeableConcept[];
        period?: {
            start?: string;
            end?: string;
        };
        related?: FhirReference[];
    };
    basedOn?: FhirReference[];
    relatesTo?: Array<{
        code?: string;
        target?: FhirReference;
    }>;
    content?: Array<{
        attachment?: FhirAttachment;
        format?: FhirCoding;
    }>;
}
export interface FhirCommunicationResource {
    resourceType: 'Communication';
    id?: string;
    status?: string;
    category?: FhirCodeableConcept[];
    subject?: FhirReference;
    recipient?: FhirReference[];
    sender?: FhirReference;
    sent?: string;
    payload?: Array<{
        contentAttachment?: FhirAttachment;
        contentReference?: FhirReference;
    }>;
    partOf?: FhirReference[];
    note?: Array<{
        text?: string;
    }>;
}
